INSERT INTO arcanos (numero, nome, descricao) VALUES (1, 'O MAGO', 'O princípio, o ponto de partida, a Unidade, o Poder.  O Mago é “o começo”; significa a capacidade para falar, atuar, estudar e escrever. É o princípio do masculino, da energia yang. Significa também, habilidade, diplomacia, astúcia, vontade, energia e poder.  Mostra claramente que se deve aceitar os riscos, pois tem mente alerta e aberta, além de grande capacidade persuasiva. Mostra ainda que o não fazer nada é pior do que fazer o mal. Logo, é preferível se aventurar do que ficar passivo esperando as coisas acontecerem, e, guiado pela razão, pela firme vontade e a fé em si mesmo, conseguirá grandes realizações, se perseverar em seus ideais.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (2, 'A SACERDOTISA', 'A mente e a Mãe Divina; a receptividade; o Bem e o Mal. A Sacerdotisa/Papisa é a “percepção espiritual e benéfica”; significa segredo, mistério, ciência, intuição, coisas escondidas, percepção das próprias necessidades espirituais e sentimento religioso. O 2 sempre será a energia de polaridade feminina, yin.Mostra que deve tornar-se mais receptivo, deve pensar bem antes de decidir qualquer coisa, ou de parar, a fim de se aprimorar. O lado negativo mostra claramente que, se não se tornar um especialista, pode desenvolver a preguiça, algumas intenções hostis e excesso de fantasias.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (3, 'A IMPERATRIZ', 'O Filho; a Consequência; o fruto do homem e da mulher. Trindade. A Imperatriz é a “cornucópia”, ou seja, a abundância, a fertilidade. Ela mostra claramente a sabedoria, a força espiritual, a ação, a inquietude, a fermentação, a incubação, a fecundidade, a geração e a iniciativa. A Imperatriz é a figura da mulher. Mostra um ser compreensivo, elegante e com total domínio sobre si mesmo; representa, também, a feminilidade como forma de expressão, de criação e de poder exercido com sutileza. Simboliza, ainda, esplendor e mesmo a mulher amada. A Imperatriz mostra o êxito nos empreendimentos, quando os pensamentos e as ações do líder são direcionados para a retidão.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (4, 'O IMPERADOR', 'Os quatro elementos; o Poder. Materialização e adaptação. O Imperador é a “majestade e o poder”. É o poder do mando e comando. Ele significa apoio, poder, estabilidade, proteção, vontade, força de execução e riqueza material. Mostra também, forte autoridade ou necessidade de consulta a uma autoridade superior. Representa a Lei, o poder público, a perseverança, a força absoluta e a certeza. O imperador é a figura do homem.  Pode ser definido como a realização dos atos dirigidos pela Ciência da Verdade, o amor à Justiça, a força da vontade  e o trabalho dos Órgãos. Ele também mostra que nada resiste a uma vontade firme, que tem como alavanca a ciência da verdade e da justiça. Resumindo, o Imperador é aquele que dirige o fluxo das energias no sentido da realização e do sucesso em qualquer atividade.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (5, 'O PAPA (HIEROFANTE)', 'A mente; o homem em expansão espiritual.  É a “opinião publica”; significa inspiração, indicação, ensino. Mostra também, dever, consciência, disposição para a vida religiosa, conselheiro, conselhos, generosidade, perdão, autoridade moral, doação dos conhecimentos. No sentido esotérico, representa a procura de um Mestre; necessidade de se conhecerem todas as facetas de um problema antes da decisão final. É importante lembrar que nada resiste a uma vontade firme, que tem como alavanca a ciência da verdade e da justiça. Combater para assegurar a sua realização é mais que um direito, é um dever. Quando o Papa aparece, significa que a realização das esperanças depende de um ser mais poderoso; é necessário conhecê-lo para obter seu apoio.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (6, 'O NAMORADO (AMANTES)', 'A Serpente; a Forma Tripla, espírito e matéria. É a “escolha emocional”; é a indecisão do ser humano frente a decisões difíceis, porém inevitáveis. Significa, também, atração, beleza e idealismo. No mundo divino, é a Ciência do Bem e do Mal. No mundo intelectual, é o equilíbrio da Necessidade e da Liberdade. No mundo físico, é o antagonismo das forças naturais, o encadeamento das causas aos efeitos. Mostra que deve ter muito cuidado com suas resoluções. Existem obstáculos que impedem o progresso. Os “azares” pairam sobre sua cabeça e a vontade vacila diante dos opostos. A indecisão é, em tudo, mais funesta do que uma má escolha. Avança ou recua, jamais hesitando.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (7, 'O CARRO', 'O 7 é a evolução. É um número mágico; 7 notas; 7 cores. Arco-íris. Misticismo. É o triunfo bem merecido; é o ser humano equilibrado e, portanto, bem-sucedido, que foi capaz de decidir corretamente. Significa também a providência, auxílio, triunfo e a dominação do Espírito sobre a Natureza. O carro mostra a capacidade humana de, através da mente, controlar o corpo (carro) num rumo certo e definido, apesar das emoções. Neste Arcano encerra-se o conjunto das primeiras sete cartas, representativas do desenvolvimento das qualidades do “homem” por meio de sua luta para sair-se vitorioso tanto sobre a matéria como sobre o espírito.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (8, 'A JUSTIÇA', 'A força superior do homem. A perfeição. Significa justiça, equidade, retidão, equilíbrio, plenitude, equilíbrio entre o bem e o mal, que deve ser conseguido pelo ser humano. É uma parada para pensar e analisar a situação. No mundo intelectual ela representa a Atração e a Repulsão. No mundo físico, a Justiça relativa, falível e limitada, que provém dos homens. A Justiça, no seu lado positivo, mostra equilíbrio, regularidade, honra, harmonia, estabilidade, ordem, Lei, virtude e integridade. No lado negativo, pode representar complicação, fanatismo, timidez, abuso, intolerância, desordem e injustiça.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (9, 'O ERMITÃO (EREMITA)', 'Os 9 meses de gestação: o fruto. O iniciado. Significa prudência, proteção, sabedoria, meditação e espírito de sacrifício. Também pode mostrar avareza, falta de sinceridade, atos imprudentes e imaturidade. Sob o peso do saber, que não encontra aplicação prática no mundo materialista, o ser necessita de uma mudança ou abertura na vida, bem como de uma busca efetiva de autoconhecimento. Resumindo, preocupações com o passado podem atrasar o desenvolvimento espiritual; exageros à parte, representam as bases desse mesmo desenvolvimento.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (10, 'A RODA DA FORTUNA', 'O Princípio. Novo ciclo, morte-ressurreição. É a sorte e a recompensa cármica. Representa fortuna, destino, elevação, ascensão, supremacia; mas também pode significar falsidade, ilusão e instabilidade. O importante é saber que para poder é necessário querer; para querer com eficácia é preciso ousar; e para ousar com êxito é preciso saber calar até o momento de agir. Para se conseguir o direito do Poder, é preciso querer pacientemente e com perseverança infatigável. Caso seja avarenta ou déspota, o sucesso conseguido pode ser ilusório, assim como ilusória será a vitória sobre a existência.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (11, 'A FORÇA', 'O domínio das emoções. Representa a atuação de uma força superior (no caso, a vontade do ser humano) sobre a força bruta - os instintos, a parte animal do ser humano. Significa ainda, energia, trabalho, ação e vitalidade. Deve sempre se lembrar que para poder é preciso crer que se pode. Avança com fé; os obstáculos são fantasmas. Para que o ser humano se torne forte, é necessário impor silêncio às fraquezas do coração; é preciso estudar o dever que é a regra do direito a praticar a justiça como se tivesse amor a ela.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (12, 'O ENFORCADO', 'Mostra sacrifício,  inércia, renúncia, resignação, utopia. O desconhecimento do caos interior ou o exterior que o cerca, aquele que se esforça em não mudar de postura. O arcano mostra a predominância do mundo material sobre o espiritual; algo não-natural. Mostra, também, uma certa crise interna que pede imediata resolução. Mais claramente, o “homem” primeiro deve “morrer” para a matéria a fim de poder ingressar no mundo espiritual, perdoando a todos aqueles que, de alguma maneira, ele acredita que lhe prejudicaram. No mundo divino significa Lei revelada. No mundo intelectual, o ensino do Dever. No mundo físico, o sacrifício voluntário, na tentativa de solucionar o problema de autocorreção. Não se pode ficar de ponta cabeça para sempre. Mudar ou morrer.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (13, 'A MORTE', 'Representa uma transformação inevitável ou mesmo um rejuvenescimento. Mostra que algo deve terminar; oportunidade de uma vida nova, desde que se consiga abrir mão da antiga. As coisas terrenas são efêmeras, e as mais altas potências são cortadas como as ervas dos campos. A carta significa também, a morte física, destruição e renovação. Mostra a libertação dos instintos materiais por uma livre e voluntária adesão da alma às Leis do Movimento Universal, que constitui em nós a criação de um segundo “homem”, o “homem” celeste. Seguido de uma carta positiva, a mudança tende a ser favorável.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (14, 'A TEMPERANÇA', 'Mostra adaptação às circunstâncias, uma metamorfose, uma mutação. Também representa, na sua parte positiva, disciplina, autocontrole, viagem bem-sucedida e sociabilidade. Na negativa, falta de personalidade, de controle e corrupção. No mundo divino, representa o movimento perpétuo da vida. No mundo intelectual, a combinação das ideias que criam a vida moral. No mundo físico, a combinação das forças da Natureza.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (15, 'O DIABO', 'Evento irrevogável. Significa força maior, destino, magia negra, mistério, atrações secretas, período de estagnação, frustração total, sensação de barreira intransponível. É a imagem da fatalidade que rebenta como a erupção de um vulcão sobre aquele que se deixa dominar pelas ilusões da matéria, quer seja ele forte ou fraco, grande ou pequeno, hábil ou ignorante. No mundo divino representa a predestinação. No mundo intelectual, o mistério. No mundo físico, o imprevisto, a fatalidade.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (16, 'A CASA DE DEUS (A TORRE)', 'Representa empáfia,  catástrofes, excessos, imprevistos, desastres, perseguição de ideias genéricas, ruína e influências más, ilusão, erros repetidos. Pode, também, dependendo do caso, mostrar doenças, falta de rumo na vida, injustiça, perda da liberdade e ausência de definição.  Aqui,  deve-se aceitar com resignação a Suprema Vontade do Onipotente, pois toda prova se encaminha para a recompensa final.  É momento de ter fé, perdoar a si e aos outros, de rever os projetos, de pesar as coisas, opiniões, objetos, seus conceitos sobre tudo e todos, de cortar definitivamente o passado.  Momento de dissolução.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (17, 'A ESTRELA', 'Renascimento da alegria, amor e esperança. Mostra influência, ascendência, inspiração, criatividade, contato com pessoas inspiradoras.  O ser humano é o ponto central das lutas dos elementos, e somente poderá equilibrar-se e realizar-se quando estabelecer equilíbrio entre eles. Esta lâmina representa também a influência dos elementos e astros em nossa vida material, mental e espiritual. Em casos especiais se uma pessoa é comprovadamente avarenta, egoísta e invejosa. Este arcano também pode mostrar doença mental, “azar”, emoções desenfreadas e mal conduzidas.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (18, 'A LUA', 'É o mundo subconsciente dos sonhos. Representa trevas, sortilégios, enfeitiçamento, aviso de algo ruim, excesso de imaginação, influências perniciosas, decepções, fraudes e pequenos prejuízos. Também pode denotar tendência a drogas e alcoolismo. É momento de se lembrar que aquele que afronta o desconhecido, procura a sua perda. Observa, escuta e cala-te. No plano divino, representa os abismos do infinito. No plano intelectual, as trevas que envolvem o Espírito quando se submete ao domínio dos instintos. No mundo físico, as decepções e os inimigos ocultos.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (19, 'O SOL', 'Triunfo, sucesso, vitalidade, vitória, êxito, satisfação, . Este é o arcano de grandes sucessos,  do presságio favorável, facilidade e clareza de expressão, boas relações, amizades leais, contentamento no amor, luz e desembaraço. Do lado esotérico, mostra grande criatividade e felicidade, o paraíso, o altruísmo e a liberação. No mundo divino, representa o Céu supremo. No mundo intelectual, a Verdade sagrada. No mundo físico, a Felicidade tranquila.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (20, 'O JULGAMENTO', 'Recomeço. Renascimento de uma nova vida. Esta lâmina significa, no seu lado positivo, regeneração, sucesso frente a uma dificuldade, proteção, despertamento, surpresa e brilho. No seu lado negativo, dependendo do caráter de quem está sob a influência do 20. Pode significar falta de ajuda, divórcio, falha num empreendimento, indecisão e rompimento de um relacionamento. O sentido esotérico nos diz que o sucesso nas relações ou empreendimentos criativos serão alcançados na luta pela vitória sobre a letargia, não adormecer na preguiça, nem no esquecimento.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (21, 'O MUNDO', 'O mundo é a representação das portas abertas. É o sucesso, a segurança, a realização, a conclusão e a recompensa. O Mundo é o arcano mais poderoso do Tarô; é uma reunião e síntese de todos os Arcanos Maiores. É a matéria dominada pelo espírito (círculo). Este, por sua vez, apresenta-se em equilíbrio entre atividade e passividade, rodeado pelos quatro elementos.  O Mundo não apresenta qualquer negatividade, porém, em casos extremos, ou seja, se a pessoa  for um ser sem qualquer espiritualidade e rancorosa, ele pode representar, na pior das hipóteses, um obstáculo a ser superado ou uma forte ligação às coisas terrenas.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (22, 'O LOUCO', 'Significa inconsciência, perturbação, loucura, novos horizontes se abrindo, entusiasmo juvenil. Também pode representar impulso cego, falta de direção e inconsequência. Aconselha-se olhar e avaliar o que possui e a tentar determinar um novo caminho, sem medo, mas com prudência. O Louco é o símbolo do homem que se torna escravo da matéria, mas também demonstra que esse mesmo homem quer melhorar, quer conhecer o desconhecido. Não durma com os olhos dos outros.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (23, 'Senhor do Bastão', 'É a carta da liderança, das novas ideias e das grandes mudanças na vida. Representa um homem do campo, bom e austero; pessoa bem-intencionada e honesta. Mostra o poder adquirido pelo mérito e pelo trabalho, sendo o símbolo da proteção das pessoas bem colocadas profissionalmente. Mostra, ainda, que se tiver vontade e fé, encontrará um grande protetor, que tudo fará por ele.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (24, 'Senhora do Bastão', 'É o símbolo de um nascimento em posição elevada ou da proteção de uma senhora da alta sociedade. Demonstra, também, a força da imaginação, da constância e da objetividade.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (25, 'Soldado do Bastão', 'Este arcano significa partida, mudança, fuga, separação e abandono.  A mudança pode ser, também, de: casa; emprego; ambiente; busca de novos horizontes. Deve lembrar-se que tanto no bem como no mal, todo trabalho produz frutos.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (26, 'Escravo do Bastão', 'Pressagia grande agitação e inquietação. Este Arcano denota aviso, advertência. Ao lado de uma figura feminina, revela êxito nos empreendimentos. Ao lado de uma figura masculina, mostrará que alguém falará por ele. É o símbolo da ruína por empreendimentos mal calculados e combinações errôneas. Mostra também profissões inferiores e mau emprego das faculdades. Este Arcano mostra que deve-se desconfiar dos interesses egoístas e das paixões que o rodeiam, se não quiser cair na servidão.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (27, 'Dez Bastões', 'Este Arcano denota prosperidade, ganho, êxito. Mostra, ainda, viagens, empreendimentos que têm toda a probabilidade de êxito e estabilidade, realizações de atos que darão alegria e segurança, estudos bem-sucedidos, mudança para melhor, e, se for um artista ou cientista, terá toda a probabilidade de ficar famoso.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (28, 'Nove Bastões', 'Este Arcano significa atraso: suspensão; adiamento; demora; obstáculo; contrariedade; sucesso com perigo de estagnação, exigindo mudança de rumos. Mostra dinheiro a receber pelo trabalho.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (29, 'Oito Bastões', 'Este Arcano significa campo, agricultura. Denota bens imóveis, divertimento, alegria, paz e tranquilidade. É sinal de viagens por causa de dinheiro e de grandes negócios; felicidade certa. Mostra, ainda, empreendimentos que podem trazer lutas e discussões, porém com final feliz.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (30, 'Sete Bastões', 'Este Arcano significa empreendimentos que trazem grandes lucros, triunfante, cheios de êxito. Mostra, também, comércio, troca, negócio, correspondência, conversa e conferência. Quando se refere ao amor, anuncia fraqueza pessoal.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (31, 'Seis Bastões', 'Este Arcano pressagia obstáculos, embaraços, atrasos, indecisões e, às vezes, insucesso nos empreendimentos, se houver falta de vontade, firmeza e perseverança. Os obstáculos ou dificuldades podem ser gerados a partir de ações internas (psíquicas, fisiológicas ou metabólicas) ou externas (problemas causados por outrem, situações imprevistas, acidentes, enganos).');
INSERT INTO arcanos (numero, nome, descricao) VALUES (32, 'Cinco Bastões', 'Este Arcano significa ouro, riqueza, opulência, luxo e abundância. Pressagia concurso de circunstâncias favoráveis ao êxito das empresas, se o consulente não exceder o fim a que se propõe. Deve evitar a raiva, o orgulho e as paixões brutais.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (33, 'Quatro Bastões', 'Este Arcano significa associação, aliança, reunião, contrato. Mostra êxito nos empreendimentos, empresas sérias e estáveis.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (34, 'Três Bastões', 'Este Arcano mostra perfeição, possibilidade de sucesso, êxito nos empreendimentos, inovações felizes, espírito de invenção. Mostra também, o término de processos com final feliz.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (35, 'Dois Bastões', 'Este arcano mostra sofrimento físico, doença, tristeza, melancolia, desolação, aflição. É a carta da dualidade, das dificuldades, da passividade._x000B_Mostra ainda, a divisão dos empreendimentos e obstáculos imprevistos.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (36, 'Um Bastão', 'Este arcano denota inteligência criadora, trabalho útil, êxito, anuncia dinheiro, herança, fortuna próxima, êxito nos negócios financeiros.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (37, 'Senhor da Taça', 'É a carta do homem honesto, íntegro, justo e de posição. Mostra amizades sinceras, benevolência de um homem poderoso. Para a mulher indica casamento com um homem de alta posição.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (38, 'Senhora da Taça', 'Este Arcano mostra um casamento rico e feliz para um homem. INSERT INTO arcanos (numero, nome, descricao) VALUES (39, 'Soldado da Taça', 'Este Arcano significa acolhimento, viagem, proposta, convite. Denota rivalidade no amor; lutas por causa de uma mulher (ou homem); adultério perigoso.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (40, 'Escravo da Taça', 'É portador de novidades (boas ou más). Denota estudo, trabalho, reflexão e observação. Indica amores infelizes, traição por meio de falsos amigos, grandes contrariedades nas afeições e casamento infeliz.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (41, 'Dez Taças', 'É o Arcano da fama e prestígio. Significa alegria, contentamento, vida feliz e rodeada de afeições, muitos amigos, muitos amores na juventude e conservação de alguns.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (42, 'Nove Taças', 'Esta lâmina significa vitória, êxito, ganho, triunfo, prosperidade, lealdade, boa-fé, franqueza e verdade. Denota união com pessoa mais velha, viúva, amores estranhos ou celibato. É necessária prudência nos desejos e na escola das afeições, embora o conjunto seja favorável.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (43, 'Oito Taças', 'Novos e felizes horizontes. Este Arcano significa alegria, prazer, satisfação e favorável aos negócios em geral. Para os “casados”, pode significar escândalos amorosos, amores proibidos, paixões violentas, divórcio,  casamento mal feito e perigo de sedução.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (44, 'Sete Taças', 'Representa o sonhador talentoso; mostra entendimento, reflexão, pensamento e espiritualidade. Denota êxito por meio de uma mulher; felicidade pelo encontro de uma mulher amorosa, porém depois de muitas lutas e peripécias.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (45, 'Seis Taças', 'Este Arcano denota união infeliz ou má escolha no casamento: por influência de parentes, por paixão desenfreada, por sedução ou desconhecimento efetivo do parceiro. Mostra, ainda, abandono, indiferença ou ruptura de casamento. É momento de se analisar o casamento. A mensagem diz também que  nosso fim está em nosso começo. É o passado, o anterior; também mostra novos conhecimentos, novas relações, novo meio.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (46, 'Cinco Taças', 'É a encruzilhada da vida. Significa legados, heranças, donativos, patrimônios e testamentos.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (47, 'Quatro Taças', 'Mudanças para melhor. Este arcano significa parentesco, família, meio social. Também mostra amores sólidos e duráveis, amizades sinceras, realização dos objetivos e aproximação de uma grande alegria.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (48, 'Três Taças', 'Esperanças concretizadas. Este Arcano significa êxito, vitória, realização, conclusão; mostra, ainda, a descoberta da cura, alívio da dor e sofrimento físico. Também mostra ternura, afeições novas, poesia, amor por um(a) virtuoso(a) jovem.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (49, 'Duas Taças', 'Compromisso. Este arcano, significa amor, ou na pior das hipóteses, paixão, simpatia, atração, amizade, afeição, união e concórdia. No caso de paixão,  pressagia rivalidade e obstáculos.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (50, 'Uma Taça', 'Casamento. Esta lâmina significa casa, residência, festa, convidados; também mostra assiduidade, perseverança e coragem. Nos assuntos do amor, pode significar perigo de sedução, paixão violenta e desenfreada, levando a conclusões precipitadas.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (51, 'Senhor do Gládio (Espada)', 'Desarranjo nos negócios. Mostra que poderá ter problemas com a justiça.  Para militares(de qualquer arma), será bem sucedido na carreira, mas fará muitos inimigos.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (52, 'Senhora do Gládio', 'Um arcano que  significa “viuvez”, privação, falta. Uma pessoa (ambos os sexos) triste e embaraçada nos seus negócios ou viúva._x000B_Se for mulher, poderá ser traída pelo companheiro ou pela pessoa que ama. Se for um homem, pressagia lutas por causa de mulheres; ódios femininos, ciúmes e magia de alguma espécie.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (53, 'Soldado do Gládio', 'Esta lâmina significa ataque; crítica, zombaria; calúnia, difamação. Mostra envolvimento com drogas, jogo, contrabando e negócios escusos. Pressagia perigo pelo fogo ou por inimigos ocultos. Se for militar (de qualquer arma), há perigo de morte nessa profissão.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (54, 'Escravo do Gládio', 'Este Arcano significa espião, observador; mostra traição de pessoa próxima, perigo de morte pública ou assassinato; grande perigo por inimigos ocultos e maus.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (55, 'Dez Gládios', 'Este arcano significa lágrimas, tristezas, lamentos e aflição.  Denota alternativas de lucros e perdas, vida cheia de infortúnios, desgostos e/ou doenças.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (56, 'Nove Gládios', 'Significa decepção, desengano, atraso nos negócios. Mostra, desgostos, inimizades poderosas, lutas misteriosas e até perigo de ser assassinado, e que é necessária prudência e discrição para vencer os obstáculos. No nível de saúde, denota doença grave.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (57, 'Oito Gládios', 'Rivalidade. Pressagia desgosto e ansiedade. Significa critica, posição duvidosa, conflito, portador de más notícias. Se for seguida do 72 (Sete Moedas) significa lágrimas, discórdia, perda de emprego e de reputação. Na área jurídica, mostra perda de processo, condenação.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (58, 'Sete Gládios', 'Mostra catástrofes imprevistas, perda de posição e esperanças irrealizáveis; possibilidade de quedas de lugares elevados. Avisa sobre perigos, observações a tempo, reprovações, pretensões sem mérito, perdas de posição, esperanças falidas.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (59, 'Seis Gládios', 'Significa indecisão, instabilidade; grandes desgostos por falta de firmeza e de iniciativa. Do lado positivo, significa passeio, passagem, viagem e notícias agradáveis e favoráveis.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (60, 'Cinco Gládios', 'Significa roubo, perda, engano, falsidade, desperdício, destruição, infelicidade, desonra, infâmia e sedução.  Uma pessoa com ideias fixas, vingativas; pressagia suicídio ou assassinato, ruína total por meio de más ideias e ideologias.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (61, 'Quatro Gládios', 'Significa solidão, retiro, segurança. Mostra um ser simples, econômico e de boa conduta. pressagia, também, afastamento da vida social, em consequência de contrariedades e desgostos.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (62, 'Três Gládios', 'Significa afastamento, partida, ausência, incidente, horror, desprezo, antipatia e aversão. Indica lutas, controvérsias, desgostos e empresas embaraçosas.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (63, 'Dois Gládios', 'Este arcano denota comunhão. Proteção contra os inimigos e grandes lutas por associações humanitárias e partidárias. Denota tanto rivalidades, quanto: afeição, ternura, simpatia, atração e benevolência.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (64, 'Um Gládio', 'É a carta das relações, das conquistas, do êxito no amor, das paixões violentas. Também mostra vantagens conquistadas com muita luta.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (65, 'Senhor da Moeda', 'Aprendizagem. A ascensão. A figura do Rei de Ouros que mostra o seu poder, experiência, capacidade e prosperidade. Para mulheres é a  proteção de um homem rico, ou casamento com um homem rico e de poder.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (66, 'Senhora da Moeda', 'A Rainha de Ouros. Representa riqueza, opulência, luxo, segurança e liberdade. Para um homem, mostra claramente um casamento (ou um enlace) com uma mulher influente e de posição.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (67, 'Soldado da Moeda', 'Significa chegada inesperada, visita. Mostra, ainda, lucro, ganho, vantagem, interesse, paz e tranquilidade. Este Arcano denota êxito nos empreendimentos, porém depois de muitas lutas; mostra que obterá fortuna, apesar dos obstáculos. Paz e tranquilidade final.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (68, 'Escravo da Moeda', 'É o mensageiro, o que traz notícias favoráveis sobre dinheiro. Também mostra trabalho, ocupação, aplicação e generosidade.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (69, 'Dez Moedas', 'É a carta da família, da casa, da mudança benéfica, da aquisição de bens pelo trabalho, do êxito em propriedades e terras. Mostra, ainda, dinheiro ganho, grande alegria.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (70, 'Nove Moedas', 'Este arcano mostra um pequeno atraso nos negócios, mas que no final obterá êxito, realização e terá segurança econômica. Este Arcano significa fortuna proveniente de herança, fontes misteriosas, estudos científicos ou metafísicos.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (71, 'Oito Moedas', 'Este arcano denota processo, contestação. Estará sujeito a dificuldades, e até o perigo de ser roubado. Mostra muitas esperanças e poucos resultados.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (72, 'Sete Moedas', 'Significa boas notícias, dinheiro, riqueza, compra, especulação, negócios. Mostra que poderá adquirir riqueza por meio do trabalho pessoal íntegro e honesto.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (73, 'Seis Moedas', 'Mostra aspirações, ambições, esperanças e desejos. Este Arcano denota bens inesperados, porém perigo de perdê-los por meio de falsos amigos.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (74, 'Cinco Moedas', 'Este arcano denota idéias, pensamentos, inspiração,  prodigalidade e também da dissipação (perda) de energia. Ele diz que é preciso olhar para si, para as próprias necessidades.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (75, 'Quatro Moedas', 'Significa recompensa, presente, herança, benefício e generosidade. Mostra que adquirirá riqueza e fortuna estável.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (76, 'Três Moedas', 'É o arcano do nascimento, da grandeza da alma, da nobreza, da celeridade, do renome. Empreendimentos habilmente dirigidos e regidos pelo trabalho feito com perfeição e amor, podem alcançar fortuna.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (77, 'Duas Moedas', 'Mostra correspondência, bilhete, carta. Pressagia obstáculos, embaraços, fortuna dividida, porém, probabilidade de associação benéfica.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (78, 'Uma Moeda', 'Significa contentamento perfeito, felicidade, êxtase, alegria, ouro, opulência, vida perfeita e com muita saúde.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (79, 'Carta 79', 'Remete aos Arcanos 16 ou 7.  Recomeço. Cautela no uso do Arcano.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (80, 'A JUSTIÇA', 'A força superior do homem. A perfeição. Significa justiça, equidade, retidão, equilíbrio, plenitude, equilíbrio entre o bem e o mal, que deve ser conseguido pelo ser humano. É uma parada para pensar e analisar a situação. No mundo intelectual ela representa a Atração e a Repulsão. No mundo físico, a Justiça relativa, falível e limitada, que provém dos homens. A Justiça, no seu lado positivo, mostra equilíbrio, regularidade, honra, harmonia, estabilidade, ordem, Lei, virtude e integridade. No lado negativo, pode representar complicação, fanatismo, timidez, abuso, intolerância, desordem e injustiça.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (81, 'Carta 81', 'Poderá haver problemas com a justiça ou da lei de causa e efeito.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (82, 'Carta 82', 'Poderá servir de escada para os outros, voluntária ou involuntariamente.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (83, 'Carta 83', 'Esta lâmina significa que haverá uma associação intelectual ou cultural.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (84, 'Carta 84', 'Significa que a pessoa deverá trabalhar com e para o povo; pode se tornar político, filantropo, humanitário.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (85, 'Carta 85', 'Significa afastamento da vida social ou perda temporária de bens ou da própria vida.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (86, 'Carta 86', 'Significa sobre alguma coisa, conseguida após muita luta e determinação.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (87, 'O DIABO', 'Evento irrevogável. Significa força maior, destino, magia negra, mistério, atrações secretas, período de estagnação, frustração total, sensação de barreira intransponível. É a imagem da fatalidade que rebenta como a erupção de um vulcão sobre aquele que se deixa dominar pelas ilusões da matéria, quer seja ele forte ou fraco, grande ou pequeno, hábil ou ignorante. No mundo divino representa a predestinação. No mundo intelectual, o mistério. No mundo físico, o imprevisto, a fatalidade.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (88, 'A CASA DE DEUS (TORRE)', 'O imprevisto. Representa catástrofes, excessos, imprevistos, desastres, perseguição de ideias genéricas, ruína e influências más. Pode, também, dependendo do caso, mostrar doenças, falta de rumo do consulente, injustiça, perda da liberdade e ausência de definição. O consulente deve aceitar com resignação a Suprema Vontade do Onipotente, pois toda prova se encaminha para a recompensa final. O consulente deve repensar seus projetos, suas opiniões, seus conceitos sobre tudo e todos.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (89, 'Carta 89', 'Significa mérito não reconhecido.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (90, 'O ERMITÃO (EREMITA)', 'Os 9 meses de gestação: o fruto. O iniciado. Significa prudência, proteção, sabedoria, meditação e espírito de sacrifício. Também pode mostrar avareza, falta de sinceridade, atos imprudentes e imaturidade. Sob o peso do saber, que não encontra aplicação prática no mundo materialista, o ser necessita de uma mudança ou abertura na vida, bem como de uma busca efetiva de autoconhecimento. Resumindo, preocupações com o passado podem atrasar o desenvolvimento espiritual; exageros à parte, representam as bases desse mesmo desenvolvimento.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (91, 'Carta 91', 'Significa que a pessoa passará por um período de solidão enquanto perdurar a influência do Arcano.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (92, 'Carta 92', 'Significa união tardia, com pessoa muito mais velha, recolhida a um asilo ou ainda uma associação com grupos ou pessoas.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (93, 'Carta 93', 'Significa um grande período de sabedoria e bons resultados.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (94, 'Carta 94', 'Significa solidão na velhice ou morte de pessoa idosa.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (95, 'Carta 95', 'Significa reconhecimento intelectual.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (96, 'Carta 96', 'Significa amores secretos e que lhe podem causar graves problemas.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (97, 'Carta 97', 'Significa decisão difícil ou solidão a muito esperada que se concretiza.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (98, 'Carta 98', 'Significa alto cargo e grande influência.');
INSERT INTO arcanos (numero, nome, descricao) VALUES (99, 'Carta 99', 'Significa muito dinheiro e riqueza material.');
